// src/BillsHistory.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function BillsHistory({ employee }) {
  const navigate = useNavigate();
  const [bills, setBills] = useState([]);

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const res = await fetch(
        `${apiBase}/bills?empld=${encodeURIComponent(employee.empld)}`
      );
      const data = await res.json();
      setBills(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error("Bills history fetch error:", err);
      setBills([]);
    }
  };

  const handleDownloadPDF = () => {
    window.print();
  };

  if (!employee) {
    return (
      <div style={centerScreen}>
        <div>Employee data not found. Please login again.</div>
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 20,
        fontFamily: "Segoe UI",
      }}
    >
      <div style={card}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button
            onClick={() => navigate("/history")}
            style={backBtn}
          >
            ⬅ Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>Bills Upload History</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555", marginTop: 6 }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        <div style={{ display: "flex", justifyContent: "flex-end", margin: "10px 0" }}>
          <button
            onClick={handleDownloadPDF}
            style={downloadBtn}
          >
            Download PDF
          </button>
        </div>

        <table style={tableStyle}>
          <thead>
            <tr>
              <th>Date</th>
              <th>File Name</th>
              <th>Preview</th>
            </tr>
          </thead>
          <tbody>
            {bills.map((b) => (
              <tr key={b.id}>
                <td>{b.created_at?.split?.("T")?.[0] || b.created_at}</td>
                <td>{b.fileName || b.filename}</td>
                <td>
                  {b.filePath && (
                    <a
                      href={`${apiBase}${b.filePath}`}
                      target="_blank"
                      rel="noreferrer"
                    >
                      Open
                    </a>
                  )}
                </td>
              </tr>
            ))}
            {bills.length === 0 && (
              <tr>
                <td colSpan="3" style={{ textAlign: "center", padding: 10 }}>
                  No bills uploaded yet.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const centerScreen = {
  minHeight: "100vh",
  background: lightGreen,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontFamily: "Segoe UI",
};

const card = {
  maxWidth: 950,
  margin: "0 auto",
  background: "#ffffff",
  borderRadius: 16,
  padding: 20,
  boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
};

const backBtn = {
  background: "transparent",
  border: "none",
  color: green,
  fontSize: 16,
  cursor: "pointer",
};

const tableStyle = {
  width: "100%",
  borderCollapse: "collapse",
  fontSize: 13,
};

const downloadBtn = {
  padding: "8px 14px",
  borderRadius: 20,
  border: "none",
  background: green,
  color: "#fff",
  fontSize: 13,
  cursor: "pointer",
};
